"use client";

import { createContext, useContext } from "react";

export interface ScrollPathContextProps {
  scrollProgress: number;
}

export const ScrollPathContext = createContext<ScrollPathContextProps>({
  scrollProgress: 0,
});

export const useScrollPath = () => useContext(ScrollPathContext);

"use client";

import React, { useRef, useState, useEffect } from "react";
import { useScroll, useMotionValueEvent } from "framer-motion";
import { ScrollPathContext } from "./ScrollPathContext";

export interface ScrollPathContainerProps {
  mode?: "scroll-jack" | "passive";
  sensitivity?: number; // Higher value means faster progress per scroll tick
  scrollLength?: number; // Custom pixel length to complete animation in scroll-jack mode
  children: React.ReactNode;
  className?: string;
}

export default function ScrollPathContainer({
  mode = "scroll-jack",
  sensitivity = 1,
  scrollLength,
  children,
  className = "",
}: ScrollPathContainerProps) {
  const [scrollProgress, setScrollProgress] = useState(0);
  const containerRef = useRef<HTMLDivElement>(null);
  const accumulatedRef = useRef(0);
  const lockRef = useRef(true);
  const touchStartRef = useRef(0);

  // Framer motion scroll hook for passive mode
  const { scrollYProgress } = useScroll({
    target: containerRef,
    offset: ["start center", "end center"],
  });

  // Track framer-motion scroll progress under passive mode
  useMotionValueEvent(scrollYProgress, "change", (latest) => {
    if (mode === "passive") {
      setScrollProgress(latest);
    }
  });

  useEffect(() => {
    if (mode !== "scroll-jack") {
      // Clean up body overflow if changing modes
      document.body.style.overflow = "";
      return;
    }

    const container = containerRef.current;
    if (!container) return;

    // Reset lock on mount/reset
    lockRef.current = true;
    accumulatedRef.current = 0;
    setScrollProgress(0);
    document.body.style.overflow = "hidden";

    const targetScrollHeight = scrollLength || window.innerHeight;

    const handleWheel = (e: WheelEvent) => {
      // If we are at the top of the page (window.scrollY === 0) and scrolling up,
      // re-lock scroll so we can reverse the drawing.
      if (!lockRef.current && window.scrollY === 0 && e.deltaY < 0) {
        lockRef.current = true;
        document.body.style.overflow = "hidden";
        accumulatedRef.current = targetScrollHeight;
      }

      if (!lockRef.current) return;

      const prev = accumulatedRef.current;
      const next = Math.max(0, Math.min(targetScrollHeight, prev + e.deltaY * sensitivity));
      accumulatedRef.current = next;
      const progress = next / targetScrollHeight;
      setScrollProgress(progress);

      // Unlock when drawing completes scrolling down
      if (next >= targetScrollHeight && e.deltaY > 0 && prev >= targetScrollHeight) {
        lockRef.current = false;
        document.body.style.overflow = "";
        return;
      }

      // Unlock when drawing goes back to zero and scrolling up
      if (next <= 0 && e.deltaY < 0 && prev <= 0) {
        lockRef.current = false;
        document.body.style.overflow = "";
        return;
      }

      if (lockRef.current) {
        e.preventDefault();
      }
    };

    const handleTouchStart = (e: TouchEvent) => {
      touchStartRef.current = e.touches[0].clientY;
    };

    const handleTouchMove = (e: TouchEvent) => {
      // Re-lock if scrolled back to top of the screen and dragging down (scroll up)
      if (!lockRef.current && window.scrollY === 0 && touchStartRef.current - e.touches[0].clientY < 0) {
        lockRef.current = true;
        document.body.style.overflow = "hidden";
        accumulatedRef.current = targetScrollHeight;
      }

      if (!lockRef.current) return;

      const deltaY = (touchStartRef.current - e.touches[0].clientY) * sensitivity;
      touchStartRef.current = e.touches[0].clientY;

      if (Math.abs(deltaY) < 1) return;

      const prev = accumulatedRef.current;
      const next = Math.max(0, Math.min(targetScrollHeight, prev + deltaY));
      accumulatedRef.current = next;
      const progress = next / targetScrollHeight;
      setScrollProgress(progress);

      if (next >= targetScrollHeight && deltaY > 0 && prev >= targetScrollHeight) {
        lockRef.current = false;
        document.body.style.overflow = "";
        return;
      }

      if (next <= 0 && deltaY < 0 && prev <= 0) {
        lockRef.current = false;
        document.body.style.overflow = "";
        return;
      }

      if (lockRef.current) {
        e.preventDefault();
      }
    };

    container.addEventListener("wheel", handleWheel, { passive: false });
    container.addEventListener("touchstart", handleTouchStart, { passive: true });
    container.addEventListener("touchmove", handleTouchMove, { passive: false });

    // Lock scroll immediately on load
    document.body.style.overflow = "hidden";

    return () => {
      container.removeEventListener("wheel", handleWheel);
      container.removeEventListener("touchstart", handleTouchStart);
      container.removeEventListener("touchmove", handleTouchMove);
      document.body.style.overflow = "";
    };
  }, [mode, sensitivity, scrollLength]);

  return (
    <ScrollPathContext.Provider value={{ scrollProgress }}>
      <div
        ref={containerRef}
        className={`w-full relative ${
          mode === "scroll-jack" ? "min-h-screen flex items-center justify-center" : ""
        } ${className}`}
      >
        {children}
      </div>
    </ScrollPathContext.Provider>
  );
}

"use client";

import { motion } from "framer-motion";
import { useScrollPath } from "../ScrollPathContext";

export interface ScrollPathCircuitProps {
  strokeWidth?: number;
  glow?: boolean;
  color?: string;
  glowColor?: string;
  className?: string;
}

const circuitPaths = [
  // Top Left Track -> Left Node
  { d: "M 100 150 L 300 150 L 350 200 L 350 450 L 580 450", nodeX: 580, nodeY: 450, triggerProgress: 0.5 },
  // Top Right Track -> Right Node
  { d: "M 1340 150 L 1140 150 L 1090 200 L 1090 450 L 860 450", nodeX: 860, nodeY: 450, triggerProgress: 0.5 },
  // Bottom Left Track -> Core Bottom
  { d: "M 100 740 L 400 740 L 450 690 L 650 690 L 720 590", nodeX: 720, nodeY: 590, triggerProgress: 0.7 },
  // Bottom Right Track -> Core Bottom
  { d: "M 1340 740 L 1040 740 L 990 690 L 790 690 L 720 590", nodeX: 720, nodeY: 590, triggerProgress: 0.7 },
  // Extra branching tracks
  { d: "M 350 280 L 420 350 L 550 350", nodeX: 550, nodeY: 350, triggerProgress: 0.4 },
  { d: "M 1090 280 L 1020 350 L 890 350", nodeX: 890, nodeY: 350, triggerProgress: 0.4 },
];

export default function ScrollPathCircuit({
  strokeWidth = 2,
  glow = true,
  color = "#00f0ff", // Cyberpunk Neon Cyan
  glowColor = "rgba(0, 240, 255, 0.4)",
  className = "",
}: ScrollPathCircuitProps) {
  const { scrollProgress } = useScrollPath();

  // Multi-stage animations:
  // Tracks animate in the first 80% of scroll.
  // The center core power-up and ambient details animate in the last 20%.
  const trackProgress = Math.min(1, scrollProgress / 0.8);
  const coreProgress = scrollProgress > 0.8 ? (scrollProgress - 0.8) / 0.2 : 0;

  return (
    <div className={`w-full px-4 flex justify-center ${className}`}>
      <svg
        width="1440"
        height="890"
        viewBox="0 0 1440 890"
        xmlns="http://www.w3.org/2000/svg"
        className="w-full h-auto max-w-7xl"
      >
        {/* Glow Filters */}
        <defs>
          <filter id="circuitGlow" x="-20%" y="-20%" width="140%" height="140%">
            <feGaussianBlur in="SourceGraphic" stdDeviation="5" />
          </filter>
        </defs>

        {/* Grid Background details */}
        <g stroke="#ffffff" strokeWidth="0.5" className="opacity-[0.03]">
          <path d="M 0 100 L 1440 100 M 0 200 L 1440 200 M 0 300 L 1440 300 M 0 400 L 1440 400 M 0 500 L 1440 500 M 0 600 L 1440 600 M 0 700 L 1440 700 M 0 800 L 1440 800" />
          <path d="M 100 0 L 100 890 M 200 0 L 200 890 M 300 0 L 300 890 M 400 0 L 400 890 M 500 0 L 500 890 M 600 0 L 600 890 M 700 0 L 700 890 M 800 0 L 800 890 M 900 0 L 900 890 M 1000 0 L 1000 890 M 1100 0 L 1100 890 M 1200 0 L 1200 890 M 1300 0 L 1300 890" />
        </g>

        {/* Circuit Tracks */}
        {circuitPaths.map((p, idx) => (
          <g key={idx}>
            {glow && (
              <motion.path
                d={p.d}
                stroke={glowColor}
                strokeWidth={strokeWidth * 3}
                fill="none"
                filter="url(#circuitGlow)"
                className="opacity-40"
                initial={false}
                animate={{ pathLength: trackProgress }}
                transition={{ type: "tween", duration: 0.1, ease: "easeOut" }}
              />
            )}
            <motion.path
              d={p.d}
              stroke={color}
              strokeWidth={strokeWidth}
              fill="none"
              initial={false}
              animate={{ pathLength: trackProgress }}
              transition={{ type: "tween", duration: 0.1, ease: "easeOut" }}
            />

            {/* Glowing nodes at path ends */}
            {trackProgress >= p.triggerProgress && (
              <motion.circle
                cx={p.nodeX}
                cy={p.nodeY}
                r={5}
                fill={color}
                initial={{ scale: 0, opacity: 0 }}
                animate={{ scale: 1, opacity: 1 }}
                exit={{ scale: 0, opacity: 0 }}
                transition={{ type: "spring", stiffness: 200, damping: 10 }}
              />
            )}
            {trackProgress >= p.triggerProgress && glow && (
              <motion.circle
                cx={p.nodeX}
                cy={p.nodeY}
                r={10}
                fill={color}
                filter="url(#circuitGlow)"
                className="opacity-50"
                initial={{ scale: 0 }}
                animate={{ scale: [1, 1.4, 1] }}
                transition={{ repeat: Infinity, duration: 2 }}
              />
            )}
          </g>
        ))}

        {/* Central Core Microchip */}
        <g transform="translate(650, 380)">
          {/* Core Outer Frame */}
          <rect
            x="0"
            y="0"
            width="140"
            height="140"
            rx="12"
            fill="none"
            stroke={color}
            strokeWidth="1.5"
            className="opacity-30"
          />

          {/* Core Power Glow */}
          {coreProgress > 0 && (
            <motion.rect
              x="10"
              y="10"
              width="120"
              height="120"
              rx="8"
              fill={color}
              filter="url(#circuitGlow)"
              style={{ opacity: coreProgress * 0.3 }}
            />
          )}

          {/* Core Inner Pattern */}
          <rect
            x="15"
            y="15"
            width="110"
            height="110"
            rx="6"
            fill="#090d16"
            stroke={color}
            strokeWidth="2"
            className="shadow-2xl"
          />

          {/* Glowing processor details */}
          <motion.g
            animate={
              coreProgress > 0.5
                ? { opacity: [0.6, 1, 0.6] }
                : { opacity: coreProgress }
            }
            transition={{ repeat: Infinity, duration: 1.5 }}
          >
            <rect x="35" y="35" width="70" height="70" rx="4" fill="none" stroke={color} strokeWidth="1" />
            <circle cx="70" cy="70" r="15" fill="none" stroke={color} strokeWidth="2" />
            {/* Inner dots */}
            <circle cx="70" cy="70" r="4" fill={color} />
          </motion.g>
        </g>
      </svg>
    </div>
  );
}

"use client";

import { motion } from "framer-motion";
import { useScrollPath } from "../ScrollPathContext";

export interface ScrollPathProcessProps {
  strokeWidth?: number;
  glow?: boolean;
  color?: string;
  steps?: Array<{ title: string; desc: string }>;
  className?: string;
}

const defaultSteps = [
  { title: "1. Brainstorm & Spec", desc: "Collaboratively refine ideas, architectural tradeoffs, and color themes before writing a single line." },
  { title: "2. Build & Sandbox", desc: "Construct components using Tailwind and Framer Motion. Test configurations inside our live control panels." },
  { title: "3. CLI Registry Publish", desc: "Publish components directly to the registry using simple cli commands to share across workspaces." },
];

export default function ScrollPathProcess({
  strokeWidth = 3,
  glow = true,
  color = "#a855f7", // Premium Purple
  steps = defaultSteps,
  className = "",
}: ScrollPathProcessProps) {
  const { scrollProgress } = useScrollPath();

  // SVG Coordinates corresponding to the card nodes
  const pathD = "M 200 350 C 400 580, 500 580, 720 580 C 940 580, 1040 580, 1240 350";

  // Card visibilities based on scroll progress
  const step1Active = scrollProgress >= 0.05;
  const step2Active = scrollProgress >= 0.5;
  const step3Active = scrollProgress >= 0.95;

  const cardVariants = {
    hidden: { scale: 0.8, opacity: 0, y: 15 },
    visible: {
      scale: 1,
      opacity: 1,
      y: 0,
      transition: { type: "spring", stiffness: 260, damping: 20 },
    },
  };

  return (
    <div className={`w-full relative h-[890px] flex items-center justify-center overflow-hidden ${className}`}>
      {/* SVG Path Background */}
      <svg
        width="1440"
        height="890"
        viewBox="0 0 1440 890"
        xmlns="http://www.w3.org/2000/svg"
        className="absolute inset-0 w-full h-full pointer-events-none"
      >
        <defs>
          <filter id="processGlow" x="-20%" y="-20%" width="140%" height="140%">
            <feGaussianBlur in="SourceGraphic" stdDeviation="6" />
          </filter>
        </defs>

        {/* Gray background track */}
        <path
          d={pathD}
          stroke="rgba(255, 255, 255, 0.05)"
          strokeWidth={strokeWidth}
          fill="none"
        />

        {/* Glow path */}
        {glow && (
          <motion.path
            d={pathD}
            stroke={color}
            strokeWidth={strokeWidth * 3}
            fill="none"
            filter="url(#processGlow)"
            className="opacity-40"
            initial={false}
            animate={{ pathLength: scrollProgress }}
            transition={{ type: "tween", duration: 0.1, ease: "easeOut" }}
          />
        )}

        {/* Primary animated path */}
        <motion.path
          d={pathD}
          stroke={color}
          strokeWidth={strokeWidth}
          fill="none"
          initial={false}
          animate={{ pathLength: scrollProgress }}
          transition={{ type: "tween", duration: 0.1, ease: "easeOut" }}
        />
      </svg>

      {/* Interactive Floating HTML Cards */}
      <div className="absolute inset-0 max-w-7xl mx-auto w-full h-full pointer-events-none">
        {/* Step 1 Card */}
        <motion.div
          variants={cardVariants}
          initial="hidden"
          animate={step1Active ? "visible" : "hidden"}
          className="absolute pointer-events-auto bg-[#18181b]/90 border border-white/10 hover:border-purple-500/30 backdrop-blur-md p-6 rounded-2xl w-[320px] shadow-2xl transition-all duration-300"
          style={{
            left: "140px",
            top: "140px",
          }}
        >
          <div className="text-xs font-mono uppercase tracking-wider text-purple-400 mb-2">Step 1</div>
          <h3 className="text-xl font-bold text-white mb-2">{steps[0]?.title}</h3>
          <p className="text-sm text-zinc-400 leading-relaxed">{steps[0]?.desc}</p>
        </motion.div>

        {/* Step 2 Card */}
        <motion.div
          variants={cardVariants}
          initial="hidden"
          animate={step2Active ? "visible" : "hidden"}
          className="absolute pointer-events-auto bg-[#18181b]/90 border border-white/10 hover:border-purple-500/30 backdrop-blur-md p-6 rounded-2xl w-[320px] shadow-2xl transition-all duration-300"
          style={{
            left: "50%",
            top: "620px",
            transform: "translateX(-50%)",
          }}
        >
          <div className="text-xs font-mono uppercase tracking-wider text-purple-400 mb-2">Step 2</div>
          <h3 className="text-xl font-bold text-white mb-2">{steps[1]?.title}</h3>
          <p className="text-sm text-zinc-400 leading-relaxed">{steps[1]?.desc}</p>
        </motion.div>

        {/* Step 3 Card */}
        <motion.div
          variants={cardVariants}
          initial="hidden"
          animate={step3Active ? "visible" : "hidden"}
          className="absolute pointer-events-auto bg-[#18181b]/90 border border-white/10 hover:border-purple-500/30 backdrop-blur-md p-6 rounded-2xl w-[320px] shadow-2xl transition-all duration-300"
          style={{
            right: "140px",
            top: "140px",
          }}
        >
          <div className="text-xs font-mono uppercase tracking-wider text-purple-400 mb-2">Step 3</div>
          <h3 className="text-xl font-bold text-white mb-2">{steps[2]?.title}</h3>
          <p className="text-sm text-zinc-400 leading-relaxed">{steps[2]?.desc}</p>
        </motion.div>
      </div>
    </div>
  );
}

export { ScrollPathContext, useScrollPath } from "./ScrollPathContext";
export { default as ScrollPathContainer } from "./ScrollPathContainer";
export { default as ScrollPathWaves } from "./variants/ScrollPathWaves";
export { default as ScrollPathCircuit } from "./variants/ScrollPathCircuit";
export { default as ScrollPathProcess } from "./variants/ScrollPathProcess";

export type { ScrollPathContainerProps } from "./ScrollPathContainer";
export type { ScrollPathWavesProps } from "./variants/ScrollPathWaves";
export type { ScrollPathCircuitProps } from "./variants/ScrollPathCircuit";
export type { ScrollPathProcessProps } from "./variants/ScrollPathProcess";
